const TARGET_CHARS = 3200;
const OVERLAP_CHARS = 400;
const SEPARATORS = ['\n## ', '\n### ', '\n\n', '\n', '. ', ' ', ''];

function split(text, separators) {
  if (text.length <= TARGET_CHARS) return [text];
  for (const sep of separators) {
    if (sep === '') break;
    if (text.includes(sep)) {
      const parts = text.split(sep);
      const out = [];
      let buf = '';
      for (const p of parts) {
        const piece = (buf ? buf + sep : '') + p;
        if (piece.length > TARGET_CHARS && buf) {
          out.push(buf);
          buf = p;
        } else {
          buf = piece;
        }
      }
      if (buf) out.push(buf);
      const flat = [];
      for (const piece of out) {
        if (piece.length > TARGET_CHARS) flat.push(...split(piece, separators.slice(1)));
        else flat.push(piece);
      }
      return flat;
    }
  }
  const out = [];
  for (let i = 0; i < text.length; i += TARGET_CHARS) out.push(text.slice(i, i + TARGET_CHARS));
  return out;
}

const input = items[0].json;
const full = (input.data || '').trim();
if (!full) return [{ json: { error: 'empty_markdown', document_id: $('Carry Context').item.json.document_id } }];

const raw = split(full, SEPARATORS).map((s) => s.trim()).filter(Boolean);

const chunks = raw.map((c, i) => {
  if (i === 0) return c;
  const prev = raw[i - 1];
  const tail = prev.slice(-OVERLAP_CHARS);
  return tail + '\n\n' + c;
});

return chunks.map((content, chunk_index) => ({
  json: {
    document_id: $('Carry Context').item.json.document_id,
    deal_id:     $('Carry Context').item.json.deal_id,
    chunk_index,
    content,
    full_text:   full
  }
}));

