const api = items[0].json;
const gathered = $('Gather Contextualized').item.json;
const embeddings = (api.embeddings || []);
if (embeddings.length !== gathered.chunks.length) {
  throw new Error(`Embedding count mismatch: ${embeddings.length} vs ${gathered.chunks.length}`);
}
const chunks = gathered.chunks.map((c, i) => {
  const e = embeddings[i] || {};
  return {
    chunk_index: c.chunk_index,
    content:     c.content,
    context:     c.context,
    embedding:   e.values || null
  };
});
if (chunks.some((c) => !c.embedding)) {
  throw new Error('Gemini returned a chunk with no embedding values');
}
return [{ json: { document_id: gathered.document_id, deal_id: gathered.deal_id, chunks } }];

